import type { RankLevel, UserResponse } from '@/types/domain.types';

export const RANK_COLORS: Record<RankLevel, string> = {
  1: '#9CA3AF',
  2: '#CD7F32',
  3: '#C0C0C0',
  4: '#FFD700',
  5: '#50C878',
  6: '#0F52BA',
  7: '#B9F2FF',
};

export const RANK_NAMES: Record<RankLevel, string> = {
  1: 'Novice',
  2: 'Beginner',
  3: 'Intermediate',
  4: 'Advanced',
  5: 'Expert',
  6: 'Elite',
  7: 'Master',
};

export function getRankColor(rank: RankLevel): string {
  return RANK_COLORS[rank];
}

export function getRankName(rank: RankLevel): string {
  return RANK_NAMES[rank];
}

export const UNRANKED_COLOR = 'oklch(30% 0 0)';

